const body = $('Receive Demo Request').first().json.body;
const geo = $input.first().json || {};

const lat = parseFloat(geo.lat);
const lon = parseFloat(geo.lon);
const geoFound = Number.isFinite(lat) && Number.isFinite(lon);

// The demo caps the radius at 2 km. Production allows up to 10 km.
function parseRadius(value) {
  const s = String(value || '').toLowerCase().trim();
  const num = parseFloat(s.replace(/[^0-9.]/g, '')) || 0;
  const meters = s.includes('km') ? num * 1000 : num;
  if (!meters) return 1000;
  return Math.min(Math.max(Math.round(meters), 100), 2000);
}

function amenityFilter(category) {
  const kw = String(category || '').toLowerCase().trim();
  if (kw.includes('cafe') || kw.includes('coffee') || kw.includes('kopi')) return '["amenity"="cafe"]';
  if (kw.includes('fast')) return '["amenity"="fast_food"]';
  if (kw.includes('bar') || kw.includes('pub')) return '["amenity"~"bar|pub"]';
  return '["amenity"~"restaurant|cafe|fast_food|bar|pub|food_court"]';
}

const radius = parseRadius(body.radius);
const category = body.category || 'restaurant';
const f = amenityFilter(category);

// When the location did not resolve we still build a valid query (around 0,0
// returns nothing fast) so the run reaches Pick Top Places and reports a
// proper reason rather than dying mid-graph.
const qLat = geoFound ? lat : 0;
const qLon = geoFound ? lon : 0;

// Cap the raw result count in the query itself (`out body N`), not just after
// the fact in Pick Top Places. A broad category like "restaurant" matches 5
// amenity types at once, and an uncapped query over a dense area can ask the
// shared public Overpass server for thousands of elements, which is what
// trips their rate limiter. 25 is comfortably more than the 5 we keep, enough
// for Pick Top Places to still choose the best-documented ones.
const RAW_LIMIT = 25;
const query = `[out:json][timeout:20];(node${f}(around:${radius},${qLat},${qLon});way${f}(around:${radius},${qLat},${qLon}););out body ${RAW_LIMIT} qt;>;out skel qt;`;

return [{ json: { query, radius, category, geoFound, lat: qLat, lon: qLon } }];

const MAX_LEADS = 5;

const meta = $('Build Overpass Query').first().json;
const elements = ($input.first().json || {}).elements || [];
const named = elements.filter((el) => el.tags && el.tags.name);

if (!meta.geoFound) {
  return [{ json: { _empty: true, reason: 'location_not_found' } }];
}
if (named.length === 0) {
  return [{ json: { _empty: true, reason: 'no_places' } }];
}

// Richer OSM entries make for a more convincing demo card, so pick the
// best-documented places first rather than whatever Overpass returned first.
function score(el) {
  const t = el.tags;
  return ['addr:street', 'phone', 'contact:phone', 'website', 'contact:website', 'cuisine', 'opening_hours']
    .filter((k) => t[k])
    .length;
}

const seen = new Set();
const picked = [];

for (const el of named.slice().sort((a, b) => score(b) - score(a))) {
  const name = String(el.tags.name).trim();
  const key = name.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  picked.push({
    json: {
      _empty: false,
      name,
      category: el.tags.amenity || null,
      cuisine: el.tags.cuisine || null,
      address: [el.tags['addr:street'], el.tags['addr:housenumber']].filter(Boolean).join(' ') || null,
      phone: el.tags.phone || el.tags['contact:phone'] || null,
      website: el.tags.website || el.tags['contact:website'] || null,
      email: el.tags.email || el.tags['contact:email'] || null,
    },
  });

  if (picked.length >= MAX_LEADS) break;
}

return picked;

