// The model is asked for raw JSON but sometimes wraps it in a fence, adds a
// sentence around it, or (reasoning-style output) prefixes the whole thing
// with a <think>...</think> block of raw chain-of-thought. That block often
// contains an example of the target JSON shape inline, so it must be removed
// before we go looking for braces, or we would grab the example instead of
// the real answer.
function stripThink(text) {
  let s = String(text || '').trim();
  // Drop a complete <think>...</think> block anywhere in the text.
  s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  // If generation was cut off before the closing tag, drop everything from
  // the opening tag onward rather than risk showing half a reasoning trace.
  const openThink = s.search(/<think>/i);
  if (openThink !== -1) s = s.slice(0, openThink).trim();
  return s;
}

function parseAnalysis(text) {
  if (!text) return null;
  let s = stripThink(text);
  s = s.replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start === -1 || end === -1) return null;
  try {
    return JSON.parse(s.slice(start, end + 1));
  } catch (e) {
    return null;
  }
}

const body = $('Receive Demo Request').first().json.body;
const meta = $('Build Overpass Query').first().json;
const places = $('Pick Top Places').all();
const analyses = $input.all();

const leads = places.map((place, i) => {
  const p = place.json;
  const raw = analyses[i] && analyses[i].json ? analyses[i].json.text : '';
  const parsed = parseAnalysis(raw) || {};
  // Last-resort fallback if the model didn't return parseable JSON at all.
  // Still sanitised, so a stray <think> block never reaches the UI even here.
  const cleanRaw = stripThink(raw);

  return {
    name: p.name,
    category: p.category,
    address: p.address,
    phone: p.phone,
    website: p.website,
    email: p.email,
    painPoints: Array.isArray(parsed.painPoints) ? parsed.painPoints.slice(0, 3).map(String) : [],
    emailSubject: String(parsed.emailSubject || ('A quick idea for ' + p.name)),
    emailBody: String(parsed.emailBody || cleanRaw || ''),
  };
});

return [{
  json: {
    runId: body.runId,
    ok: true,
    leads,
    stats: {
      placesScanned: places.length,
      leadsEnriched: leads.length,
      radius: meta.radius,
      category: meta.category,
    },
  },
}];

const body = $('Receive Demo Request').first().json.body;
const incoming = $input.first().json || {};

// Reached either from the "no usable places" branch or from the Overpass error
// output, so work out which one this is.
const reason = incoming.error ? 'upstream_busy' : (incoming.reason || 'no_places');

return [{
  json: {
    runId: body.runId,
    ok: false,
    reason,
    leads: [],
    stats: { placesScanned: 0, leadsEnriched: 0 },
  },
}];

// Belt-and-suspenders pass, right before the payload leaves n8n for good.
// Build Demo Payload already strips a leaked <think> block per lead, but this
// node catches anything that slips through it too — a prompt edit, a model
// swap, or a manual test run wired differently — so raw chain-of-thought can
// never reach the website UI regardless of which upstream node produced it.
function stripThink(value) {
  if (typeof value !== 'string') return value;
  let s = value.trim();
  s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  const openThink = s.search(/<think>/i);
  if (openThink !== -1) s = s.slice(0, openThink).trim();
  return s;
}

const payload = $input.first().json;

const leads = Array.isArray(payload.leads)
  ? payload.leads.map((lead) => ({
      ...lead,
      emailSubject: stripThink(lead.emailSubject),
      emailBody: stripThink(lead.emailBody),
      painPoints: Array.isArray(lead.painPoints) ? lead.painPoints.map(stripThink) : lead.painPoints,
    }))
  : payload.leads;

return [{ json: { ...payload, leads } }];
